import Image from '../Assets/Portrait2.jpg'
import book1 from '../Assets/chapter-house-dune.jpg'
import book2 from '../Assets/fingerprint_of_gods.jpg'
import book3 from '../Assets/economics.jpg'
import python_img from '../Assets/technologies/python.png'
import flask_img from '../Assets/technologies/flask.png'
import javascript_img from '../Assets/technologies/javascript.png'
import react_img from '../Assets/technologies/react.png'
import html_img from '../Assets/technologies/html.png'
import css_img from '../Assets/technologies/css.png'
import mui_img from '../Assets/technologies/mui.png'
import numpy_img from '../Assets/technologies/numpy.png'
import pandas_img from '../Assets/technologies/pandas.png'
import github_img from '../Assets/technologies/github2.png'
import node_img from '../Assets/technologies/node.png'
import render_img from '../Assets/technologies/render.png'
import Box from '@mui/material/Box';
import Grid from '@mui/material/Grid';
import Typography from '@mui/material/Typography';
import Container from '@mui/material/Container';
const books = [book1, book2, book3]

const gridItem = (name, path) => {
    return (
        <Container
          sx={{
            width: '15rem',
            height: '8rem',
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            bgcolor: '#292929',
            m: 'auto',
            p: 1,
            borderRadius: '10px',
            transition: '0.5s',
            '&:hover': { transform: 'scale(1.05)' }
          }}
        >
          <Box
            component='img'
            src={path}
            alt={`${name} logo`}
            height='5rem'
            mr={2}
          />
          <Typography color='#e1e1e1'>{name}</Typography>
        </Container>
    );
};



function About() {
    console.log(books)
    return (
        <Container 
        id='intro'
        maxWidth='none'
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-evenly',
          mt: '25vh',
          mb: '25vh',
          width: '75%',
        }}
        >
           <Box
            component='img'
            src={selfie_jpg}
            alt='headshot of Kyle Schneider'
            sx={{
              height: '35%',
              width: '35%',
              borderRadius: '10px',
            }}
          />
          <Box textAlign='center'>
            <Typography variant='h1'>Kyle Schneider</Typography>
            <Typography variant='h2'>Software Developer</Typography>
            <Typography>
              I am a software developer with a passion for learning and creating. 
              <br />
              I use my background in mathematics and science to solve problems and build applications.
            </Typography>
          </Box>


            <Box sx={{ display: 'flex', justifyContent: 'center' }}>
            <Grid container spacing={4}>
              <Grid item xs={3}>
                {gridItem('Python', python_img)}
              </Grid>
              <Grid item xs={3}>
                {gridItem('Flask', flask_img)}
              </Grid>
              <Grid item xs={3}>
                {gridItem('NumPy', numpy_img)}
              </Grid>
              <Grid item xs={3}>
                {gridItem('Pandas', pandas_img)}
              </Grid>
              <Grid item xs={3}>
                {gridItem('JavaScript', javascript_img)}
              </Grid>
              <Grid item xs={3}>
                {gridItem('NodeJS', node_img)}
              </Grid>              
              <Grid item xs={3}>
                {gridItem('React', react_img)}
              </Grid>
              <Grid item xs={3}>
                {gridItem('Material UI', mui_img)}
              </Grid>
              <Grid item xs={3}>
                {gridItem('HTML5', html_img)}
              </Grid>
              <Grid item xs={3}>
                {gridItem('CSS3', css_img)}
              </Grid>
              <Grid item xs={3}>
                {gridItem('GitHub', github_img)}
              </Grid>    
              <Grid item xs={3}>
                {gridItem('Render', render_img)}
              </Grid>                            
            </Grid>
          </Box>

          <Box>
                {/* Books */}
                <Typography 
                  variant='h3' 
                  textAlign='center'
                  sx={{ mt: '5vh' }}
                >
                  Books I'm Reading
                </Typography>
                <Box 
                  display='flex' 
                  flexDirection='row' 
                  justifyContent='center'  
                  alignItems='center'
                >
                    {books.map((book, index) => {
                        return (
                            <Box 
                              key={index}
                              component='img'   
                              src={book} 
                              alt='' 
                              sx={{
                                height: '18vw',
                                width: '12vw',
                                mx: 2
                              }}
                            />
                        );
                    })}
                </Box>
            </Box>


        </Container>
    )
}
export default About
